std::string WebDXFeatureToString(WebDXFeature value) {
  const char *str = WebDXFeatureToStringHelper(value);
  if (!str) {
    return base::StringPrintf("Unknown WebDXFeature value: %i", static_cast<int32_t>(value));
  }
  return str;
}

std::ostream& operator<<(std::ostream& os, WebDXFeature value) {
  return os << WebDXFeatureToString(value);
}

